class HybridWebViewActivity : ComponentActivity() {

    private lateinit var hybridWebView: HybridWebView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        hybridWebView = HybridWebView(this).apply {
            layoutParams = android.widget.FrameLayout.LayoutParams(
                android.widget.FrameLayout.LayoutParams.MATCH_PARENT,
                android.widget.FrameLayout.LayoutParams.MATCH_PARENT
            )
        }
        setContentView(hybridWebView)

        val startUrl = intent.getStringExtra(EXTRA_URL) ?: "https://example.com"
        hybridWebView.loadUrl(startUrl)
    }

    override fun onBackPressed() {
