class HybridWebView @JvmOverloads constructor(
    context: Context,
    attrs: AttributeSet? = null
) : WebView(context, attrs) {

    private val prefs: SharedPreferences =
        context.getSharedPreferences("hybrid_webview_prefs", Context.MODE_PRIVATE)

    private val mainScope = CoroutineScope(Dispatchers.Main)

    private val cameraLauncherOwner = context.findActivity()
        ?: throw IllegalStateException("HybridWebView must be created with an Activity context")

    private var pendingCameraRequestId: String? = null
    private var pendingCameraOutputUri: Uri? = null

    private val requestCameraPermission = cameraLauncherOwner.registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { granted ->
        val reqId = pendingCameraRequestId
        if (reqId != null) {
            if (granted) {
                launchCamera(reqId)
            } else {
                respondError(reqId, "PERMISSION_DENIED", "Camera permission denied")
            }
        }
    }

    private val takePicture = cameraLauncherOwner.registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result: ActivityResult ->
        val reqId = pendingCameraRequestId
        val outputUri = pendingCameraOutputUri
        pendingCameraRequestId = null
        pendingCameraOutputUri = null

        if (reqId == null) return@registerForActivityResult

        if (result.resultCode == Activity.RESULT_OK && outputUri != null) {
            val data = JSONObject()
                .put("uri", outputUri.toString())
                .put("path", outputUri.toString())
            respondOk(reqId, data)
        } else {
            respondError(reqId, "CANCELLED", "Camera cancelled")
        }
    }

    init {
        configureSettings()
        webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                val url = request?.url?.toString() ?: return false
                return if (url.startsWith("tel:") || url.startsWith("mailto:") || url.startsWith("sms:")) {
                    runCatching {
                        context.startActivity(Intent(Intent.ACTION_VIEW, Uri.parse(url)))
                    }
                    true
                } else {
                    false
                }
            }
        }
        webChromeClient = object : WebChromeClient() {
            override fun onPermissionRequest(request: PermissionRequest?) {
                if (request == null) return
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
                    request.grant(request.resources)
                }
            }

            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                return false
            }
        }

        addJavascriptInterface(NativeBridge(), "NativeBridge")
    }

    private fun configureSettings() {
        val s = settings
        s.javaScriptEnabled = true
        s.domStorageEnabled = true
        s.databaseEnabled = true
        s.allowFileAccess = true
        s.allowContentAccess = true
        s.cacheMode = WebSettings.LOAD_DEFAULT
        s.useWideViewPort = true
        s.loadWithOverviewMode = true
        s.mediaPlaybackRequiresUserGesture = false
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            s.safeBrowsingEnabled = true
        }
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
            s.mixedContentMode = WebSettings.MIXED_CONTENT_COMPATIBILITY_MODE
        }
        WebView.setWebContentsDebuggingEnabled(BuildConfig.DEBUG)
    }

    @Keep
    inner class NativeBridge {

        @JavascriptInterface
        fun ping(requestId: String) {
            respondOk(requestId, JSONObject().put("pong", true))
        }

        // ---- Local Storage (native-backed) ----

        @JavascriptInterface
        fun storageGet(requestId: String, key: String) {
            val value = prefs.getString(key, null)
            val data = JSONObject()
                .put("key", key)
                .put("value", value)
            respondOk(requestId, data)
        }

        @JavascriptInterface
        fun storageSet(requestId: String, key: String, value: String?) {
            prefs.edit().putString(key, value).apply()
            respondOk(requestId, JSONObject().put("key", key))
        }

        @JavascriptInterface
        fun storageRemove(requestId: String, key: String) {
            prefs.edit().remove(key).apply()
            respondOk(requestId, JSONObject().put("key", key))
        }

        @JavascriptInterface
        fun storageClear(requestId: String) {
            prefs.edit().clear().apply()
            respondOk(requestId, JSONObject().put("cleared", true))
        }

        // ---- Camera ----
        // Returns: { uri: "content://...", path: "content://..." }
        @JavascriptInterface
        fun openCamera(requestId: String) {
            pendingCameraRequestId = requestId

            val granted = ContextCompat.checkSelfPermission(
                context,
                Manifest.permission.CAMERA
            ) == PackageManager.PERMISSION_GRANTED

            if (!granted) {
                requestCameraPermission.launch(Manifest.permission.CAMERA)
                return
            }
            launchCamera(requestId)
        }

        // ---- Push Notifications ----
        // Returns: { token: "..." }
        @JavascriptInterface
        fun getPushToken(requestId: String) {
            mainScope.launch {
                try {
                    val token = FirebaseMessaging.getInstance().token.await()
                    respondOk(requestId, JSONObject().put("token", token))
                } catch (t: Throwable) {
                    respondError(requestId, "PUSH_TOKEN_ERROR", t.message ?: "Failed to get push token")
                }
            }
        }

        // Requests notification permission on Android 13+
        @JavascriptInterface
        fun requestNotificationPermission(requestId: String) {
            val activity = context.findActivity()
            if (activity == null) {
                respondError(requestId, "NO_ACTIVITY", "No Activity context")
                return
            }

            if (Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU) {
                respondOk(requestId, JSONObject().put("granted", true))
                return
            }

            val permission = Manifest.permission.POST_NOTIFICATIONS
            val granted = ContextCompat.checkSelfPermission(context, permission) == PackageManager.PERMISSION_GRANTED
            if (granted) {
                respondOk(requestId, JSONObject().put("granted", true))
                return
            }

            val launcher = activity.registerForActivityResult(
                ActivityResultContracts.RequestPermission()
            ) { isGranted ->
                respondOk(requestId, JSONObject().put("granted", isGranted))
            }
            launcher.launch(permission)
        }
    }

    private fun launchCamera(requestId: String) {
        val activity = context.findActivity()
        if (activity == null) {
            respondError(requestId, "NO_ACTIVITY", "No Activity context")
            return
        }

        val imagesDir = File(activity.cacheDir, "images").apply { mkdirs() }
        val outFile = File(imagesDir, "capture_${System.currentTimeMillis()}.jpg")
        val authority = "${activity.packageName}.fileprovider"
        val uri = FileProvider.getUriForFile(activity, authority, outFile)

        pendingCameraOutputUri = uri

        val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
            putExtra(MediaStore.EXTRA_OUTPUT, uri)
            addFlags(Intent.FLAG_GRANT_WRITE_URI_PERMISSION)
            addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
        }

        val canResolve = intent.resolveActivity(activity.packageManager) != null
        if (!canResolve) {
            pendingCameraRequestId = null
            pendingCameraOutputUri = null
            respondError(requestId, "NO_CAMERA_APP", "No camera app available")
            return
        }

        takePicture.launch(intent)
    }

    private fun respondOk(requestId: String, data: JSONObject = JSONObject()) {
        val payload = JSONObject()
            .put("requestId", requestId)
            .put("ok", true)
            .put("data", data)

        dispatchToWeb("window.__nativeBridge && window.__nativeBridge.onResult && window.__nativeBridge.onResult(${payload.toString()});")
    }

    private fun respondError(requestId: String, code: String, message: String) {
        val error = JSONObject()
            .put("code", code)
            .put("message", message)

        val payload = JSONObject()
            .put("requestId", requestId)
            .put("ok", false)
            .put("error", error)

        dispatchToWeb("window.__nativeBridge && window.__nativeBridge.onResult && window.__nativeBridge.onResult(${payload.toString()});")
    }

    private fun dispatchToWeb(js: String) {
        post {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.KITKAT) {
                evaluateJavascript(js, null)
            } else {
                loadUrl("javascript:$js")
            }
        }
    }
}

fun Context.findActivity(): ComponentActivity? {
    var ctx = this
    while (true) {
        when (ctx) {
            is ComponentActivity -> return ctx
            is android.content.ContextWrapper -> {
                val base = ctx.baseContext ?: return null
                if (base === ctx) return null
                ctx = base
            }
            else -> return null
        }
    }
}